// Enable calendars overlay
core.setStelProperty("Calendars.enabled", true);

// Check if enabled
var isEnabled = core.getStelProperty("Calendars.enabled");
core.debug("Calendars enabled: " + isEnabled);

// Enable custom text color
core.setStelProperty("Calendars.flagTextColorOverride", true);

// Set custom color
core.setStelProperty("Calendars.textColor", core.vec3f(1.0, 0.8, 0.5));

if (Calendars.isEnabled()) {
    core.debug("Calendars overlay is visible");
}

// Export current calendar data to HTML
Calendars.exportCalendars();
core.debug("Calendar data exported to Calendars.html");

if (Calendars.isGregorianDisplayed()) {
    core.debug("Gregorian calendar is visible");
}

// Set text color to bright white
var white = core.vec3f(1.0, 1.0, 1.0);
Calendars.setTextColor(white);
Calendars.setFlagTextColorOverride(true);

if (Calendars.getFlagTextColorOverride()) {
    core.debug("Using custom text color");
}

// Get current Gregorian date as array
var date = GregorianCalendar.getDate();
core.debug("Year:", date[0], "Month:", date[1], "Day:", date[2]);

// Check if year 2000 is leap
var isLeap = GregorianCalendar.isLeap(2000);
core.debug("2000 is leap:", isLeap);

// Get Easter date for a year
var easterRD = GregorianCalendar.easter(2024);
var easterDate = GregorianCalendar.getFormattedDateString();

// Set Stellarium date from Gregorian date
GregorianCalendar.setDate([2024, 12, 25]);

// Convert Gregorian to RD (Rata Die) number
var rd = GregorianCalendar.fixedFromGregorian([2024, 3, 14]);
core.debug("RD number:", rd);

// Convert RD back to Gregorian
var greg = GregorianCalendar.gregorianFromFixed(rd);
core.debug("Date:", greg[0], greg[1], greg[2]);

// Get current Julian date
var julian = JulianCalendar.getDate();
core.debug("Julian:", julian[0], julian[1], julian[2]);

// Check if Julian year is leap
var isLeap = JulianCalendar.isLeap(1700);
core.debug("Julian 1700 is leap:", isLeap); // true (different from Gregorian)

// Convert Gregorian to Julian date
var rd = GregorianCalendar.fixedFromGregorian([1582, 10, 4]);
var julianDate = JulianCalendar.julianFromFixed(rd);
core.debug("Last Julian date:", julianDate);

// Set Stellarium date using Julian calendar
JulianCalendar.setDate([1582, 10, 4]);

// Get current Islamic date
var islamic = IslamicCalendar.getDate();
core.debug("Islamic year:", islamic[0], "month:", islamic[1], "day:", islamic[2]);

// Get formatted Islamic date string
var dateStr = IslamicCalendar.getFormattedDateString();
core.debug("Islamic date:", dateStr);

// Set Stellarium date using Islamic calendar
IslamicCalendar.setDate([1445, 9, 1]); // First day of Ramadan

// Get current Hebrew date
var hebrew = HebrewCalendar.getDate();
core.debug("Hebrew year:", hebrew[0], "month:", hebrew[1], "day:", hebrew[2]);

// Check if Hebrew year is leap (has Adar I)
// Set date for Passover
HebrewCalendar.setDate([5784, 7, 15]);
var passoverStr = HebrewCalendar.getFormattedDateString();

// Get current Chinese date
var chinese = ChineseCalendar.getDate();
core.debug("Cycle:", chinese[0], "Year:", chinese[1], "Month:", chinese[2], "Leap:", chinese[3], "Day:", chinese[4]);

// Get Chinese year name (e.g., "Dragon")
var yearName = ChineseCalendar.yearName(chinese[1]);
core.debug("Year animal:", yearName.second);

// Get Chinese day name
var dayName = ChineseCalendar.dayName(ChineseCalendar.getRD());
core.debug("Day name:", dayName.second);

// Get solar terms for current date
var solarTerms = ChineseCalendar.getSolarTermStrings();
core.debug("Major term:", solarTerms.first, "Minor term:", solarTerms.second);

// Set Stellarium date to Chinese New Year
ChineseCalendar.setDate([78, 1, 1, 0, 1]); // cycle 78, year 1, month 1, not leap, day 1

// Get Chinese New Year in Gregorian year
var newYearRD = ChineseCalendar.newYearOnOrBefore(GregorianCalendar.fixedFromGregorian([2024, 1, 1]));

// Get current Japanese date
var japanese = JapaneseCalendar.getDate();
core.debug("Japanese:", japanese[0], japanese[1], japanese[2], japanese[3], japanese[4]);

// Get Japanese year (Era system)
var yearNum = JapaneseCalendar.japaneseYear(japanese[0], japanese[1]);
core.debug("Japanese year number:", yearNum);

// Get solar terms
var terms = JapaneseCalendar.getSolarTermStrings();

// Get current Korean date
var korean = KoreanCalendar.getDate();
core.debug("Korean:", korean[0], korean[1], korean[2], korean[3], korean[4]);

// Get Korean year in Danki system (2333 BCE +)
var dankiYear = KoreanCalendar.koreanYear(korean[0], korean[1]);

// Calculate Korean age (different from Western age)
var birthdate = KoreanCalendar.koreanFromFixed(GregorianCalendar.fixedFromGregorian([2000, 1, 1]));
var age = KoreanCalendar.koreanAge(birthdate, GregorianCalendar.fixedFromGregorian([2024, 1, 1]));
core.debug("Korean age:", age);

// Get current Vietnamese date
var viet = VietnameseCalendar.getDate();
core.debug("Vietnamese:", viet[0], viet[1], viet[2], viet[3], viet[4]);

// Get year name in 60-year cycle
var yearName = VietnameseCalendar.yearName(viet[1]);
core.debug("Year name:", yearName.second);

// Get solar terms
var terms = VietnameseCalendar.getSolarTermStrings();

