var tibetan = TibetanCalendar.getDate();
core.debug("Year:", tibetan[0], "Month:", tibetan[1], "Day:", tibetan[3]);

// Get Tibetan sexagesimal year name
var yearName = TibetanCalendar.tibetanSexagesimalYear(tibetan[0]);
