// Get Losar (New Year) date for a Tibetan year
var losarRD = TibetanCalendar.losar(tibetan[0]);

// Get current Old Hindu Solar date
var oldHindu = OldHinduSolarCalendar.getDate();

// Set output style (0=Vedic, 1=Sanskrit, 2=Zodiacal)
OldHinduSolarCalendar.setMonthStyle(2);

// Get Jovian year (60-year cycle)
var jovian = OldHinduSolarCalendar.jovianYear(OldHinduSolarCalendar.getRD());

// Get current RD (Rata Die) number
var rd = Calendar.rdNow();
core.debug("Current RD:", rd);

// Convert between JD and RD
var jd = Calendar.jdFromFixed(rd, true);
var rd2 = Calendar.fixedFromJD(jd, true);

// Get day of week (0=Sunday to 6=Saturday)
var dow = Calendar.dayOfWeekFromFixed(rd);
var weekdays = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
core.debug("Today is:", weekdays[dow]);

// Get sunrise/sunset times
var rdInt = Math.floor(rd);
var sunrise = Calendar.sunrise(rdInt);
var sunset = Calendar.sunset(rdInt);
core.debug("Sunrise fraction:", sunrise, "Sunset fraction:", sunset);

// Get moon phase (0=new, 90=first quarter, 180=full, 270=last quarter)
var moonPhase = Calendar.lunarPhase(rd);
core.debug("Moon phase degrees:", moonPhase);

// Get next new moon
var newMoon = Calendar.newMoonAtOrAfter(rd);

// Get solar longitude (0=vernal equinox, 90=summer solstice, etc.)
var sunLng = Calendar.solarLongitude(rd);
core.debug("Solar longitude:", sunLng);

// Get equation of time (in days)
var eot = Calendar.equationOfTime(rd);
core.debug("Equation of time (days):", eot);

// Check if crescent moon is visible (Islamic criterion)
var visible = Calendar.visibleCrescent(rdInt);

// Get Italian hour (from sunset)
var italianHour = Calendar.italianFromLocal(rd);

// Convert between time systems
var localTime = Calendar.localFromUniversal(rd);
var universalTime = Calendar.universalFromLocal(rd);

